type SheetSummary = {
  name: string;
  state: "visible" | "hidden" | "veryHidden";
  rowCount: number;
  columnCountEstimate: number;
  sampleHeaders: string[];
  nonEmptyCellCountEstimate: number;
  melMentions: number;
};

/** KPIs from worksheet "Asset Manager" row 2: F2–J2 (MC rate, fleet total, FMC, NMC, surplus). */
type AssetManagerKpis = {
  sheetFound: boolean;
  mcRatePercent: number | null;
  fleetTotal: number | null;
  fmc: number | null;
  nmc: number | null;
  surplus: number | null;
};

/** Per-row breakdown from the Asset Manager sheet — one row per unit/category
 *  (label is column A, numeric columns reuse the same F–J layout as the totals
 *  row). NCE = "Nuclear Certified Equipment" rows are flagged so the UI can group them. */
type AssetManagerBreakdownRow = {
  label: string;
  mcRatePercent: number | null;
  fleetTotal: number | null;
  fmc: number | null;
  nmc: number | null;
  surplus: number | null;
  isNce: boolean;
  isTotal: boolean;
};

type AnalysisResult = {
  workbookFileName: string;
  receivedAtIso: string;
  dateKey: string;
  from: string;
  to: string;
  subject: string;
  workbookBytes: number;
  assetManager: AssetManagerKpis;
  assetManagerBreakdown?: AssetManagerBreakdownRow[];
  sheetSummaries: SheetSummary[];
  totalVisibleSheets: number;
  totalHiddenSheets: number;
  totalRowsAcrossSheets: number;
  melMentionsBySheet: Record<string, number>;
  melMentionsTotal: number;
};

type HistoryEntryDiff = {
  previousDateKey: string | null;
  deltaTotalRows: number | null;
  deltaMelMentionsTotal: number | null;
  deltaSheetsVisible: number | null;
};

type HistoryEntry = {
  dateKey: string;
  receivedAtIso: string;
  workbookFileName: string;
  workbookKey: string;
  analysisKey: string;
  totalVisibleSheets: number;
  totalHiddenSheets: number;
  totalRowsAcrossSheets: number;
  melMentionsTotal: number;
  diff: HistoryEntryDiff;
};

type HistoryIndex = {
  updatedAtIso: string;
  entries: HistoryEntry[];
};

/** Report order for rebuild / replay: calendar day, then ingest time (ties: workbook key). */
function sortHistoryEntriesChronologically(entries: HistoryEntry[]): HistoryEntry[] {
  return [...entries].sort((a, b) => {
    const d = a.dateKey.localeCompare(b.dateKey);
    if (d !== 0) return d;
    const t1 = a.receivedAtIso ?? "";
    const t2 = b.receivedAtIso ?? "";
    if (t1 !== t2) return t1.localeCompare(t2);
    return a.workbookKey.localeCompare(b.workbookKey);
  });
}

export default {
  async email(message: ForwardableEmailMessage, env: Env, ctx: ExecutionContext): Promise<void> {
    if (!isAuthorizedSender(message.from, env)) {
      message.setReject("Unauthorized sender");
      return;
    }

    const parsed = await PostalMime.parse(message.raw, { attachmentEncoding: "arraybuffer" });
    const abuseIngest = parseAbuseEmailIngestFromTo(message.to || "");
    if (abuseIngest) {
      const caseRow = await findCaseByEmailToken(env, abuseIngest.token);
      if (!caseRow) {
        console.warn(
          JSON.stringify({
            level: "warn",
            message: "abuse ingest email: unknown token",
            to: message.to,
            from: message.from,
          }),
        );
        return;
      }
      const atts = (parsed.attachments || []).map((a) => ({
        filename: a.filename ?? undefined,
        mimeType: a.mimeType,
        content: normalizeAttachmentBinary(a.content),
      }));
      const n = await ingestAbuseDamEmailFiles(env, caseRow, atts, message.from, abuseIngest.routeKind);
      if (n > 0) {
        await addAbuseNote(
          env,
          caseRow.id,
          "Email ingest: " + n + " file(s) attached from " + (message.from || "unknown"),
          "system-email",
        );
      }
      return;
    }

    const workbookAttachment = pickWorkbookAttachment(parsed.attachments, env.EXPECTED_ATTACHMENT_NAME);
    if (!workbookAttachment) {
      console.warn(
        JSON.stringify({
          level: "warn",
          message: "No .xlsx attachment found on inbound email",
          from: message.from,
          to: message.to,
          subject: parsed.subject ?? "",
        }),
      );
      return;
    }

    const workbookBytes = normalizeAttachmentBinary(workbookAttachment.content);
    if (workbookBytes.byteLength > parseMaxAttachmentBytes(env.MAX_ATTACHMENT_BYTES)) {
      message.setReject("Attachment too large");
      return;
    }

    const now = new Date();
    const subject = parsed.subject ?? "";
    const safeName = sanitizeFileName(workbookAttachment.filename ?? "vehicle-etic.xlsx");
    const dateKeyFromSubject = parseReportDateKeyFromSubject(subject);
    const dateKeyFromFile = parseReportDateKeyFromFileName(safeName);
    const dateKey = dateKeyFromSubject ?? dateKeyFromFile ?? receiptDayDateKey(now, env);
    const tz = (env.INGEST_TIMEZONE ?? "").trim();
    console.log(
      JSON.stringify({
        level: "info",
        message: "etic_workbook_email_received",
        dateKey,
        dateKeySource: dateKeyFromSubject
          ? "subject"
          : dateKeyFromFile
            ? "filename"
            : tz
              ? "local-receipt-day"
              : "utc-receipt-day",
        ingestTimezone: tz || null,
        subjectLen: subject.length,
        from: message.from,
        to: message.to,
      }),
    );
    const workbookKey = `workbooks/${dateKey}/${safeName}`;
    const analysisKey = `analyses/${dateKey}.json`;

    await env.ETIC_BUCKET.put(workbookKey, workbookBytes, {
      httpMetadata: {
        contentType:
          workbookAttachment.mimeType ||
          "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
      },
      customMetadata: {
        from: message.from,
        to: message.to,
        subject,
      },
    });

    const ingestContext = {
      dateKey,
      workbookKey,
      analysisKey,
      safeName,
      from: message.from,
      to: message.to,
      subject,
    };

    try {
      const analysis = await analyzeWorkbook({
        binary: workbookBytes,
        fileName: safeName,
        receivedAtIso: now.toISOString(),
        dateKey,
        from: message.from,
        to: message.to,
        subject,
      });

      await env.ETIC_BUCKET.put(analysisKey, JSON.stringify(analysis, null, 2), {
        httpMetadata: { contentType: "application/json; charset=utf-8" },
      });

      await upsertSnapshotRow(env, analysis, workbookKey);

      const history = await loadMergedHistory(env);
      const upsertedHistory = upsertHistoryEntry(history, analysis, workbookKey, analysisKey);
      await env.ETIC_BUCKET.put(
        "history/index.json",
        JSON.stringify(upsertedHistory, null, 2),
        {
          httpMetadata: { contentType: "application/json; charset=utf-8" },
        },
      );
      await env.ETIC_BUCKET.put(
        "analyses/latest.json",
        JSON.stringify(analysis, null, 2),
        {
          httpMetadata: { contentType: "application/json; charset=utf-8" },
        },
      );

      // Keep the email event fast enough to avoid CPU-limit drops by deferring
      // workbook-heavy WO/MEL extraction to background work.
      ctx.waitUntil((async () => {
        try {
          const summary = await ingestCurrentWorkbookIntoD1(env, dateKey, workbookBytes, now.toISOString());
          console.log(
            JSON.stringify({
              level: "info",
              message: "Background WO/MEL ingest complete",
              dateKey,
              processed: summary.processed,
              total: summary.total,
            }),
          );
        } catch (error) {
          console.error(
            JSON.stringify({
              level: "error",
              message: "Background WO/MEL D1 ingest failed",
              dateKey,
              error: error instanceof Error ? error.message : String(error),
            }),
          );
        }
      })());
    } catch (err) {
      const messageText = err instanceof Error ? err.message : String(err);
      const stack = err instanceof Error ? err.stack : undefined;
      const failedAtIso = new Date().toISOString();
      const record = {
        ...ingestContext,
        failedAtIso,
        error: messageText,
        stack,
      };
      const stamp = failedAtIso.replace(/[:.]/g, "-");
      try {
        await env.ETIC_BUCKET.put(`ingest-errors/${dateKey}_${stamp}.json`, JSON.stringify(record, null, 2), {
          httpMetadata: { contentType: "application/json; charset=utf-8" },
        });
        await env.ETIC_BUCKET.put("ingest-errors/latest.json", JSON.stringify(record, null, 2), {
          httpMetadata: { contentType: "application/json; charset=utf-8" },
        });
      } catch (_persistErr) {
        /* best-effort — still log below */
      }
      console.error(
        JSON.stringify({
          level: "error",
          message: "email ingest failed after workbook was stored (see R2 ingest-errors/)",
          ...record,
        }),
      );
    }
  },

  async fetch(request: Request, env: Env, ctx: ExecutionContext): Promise<Response> {
    const url = new URL(request.url);

    if (url.pathname === "/healthz") {
      return Response.json({ ok: true, service: "etic-email-automation" });
    }

    if (url.pathname === "/favicon.ico") {
      return new Response(null, { status: 204, headers: { "cache-control": "public, max-age=86400" } });
    }

    if (url.pathname === "/api/history") {
      return Response.json(await loadMergedHistory(env), { headers: cacheHeaders() });
    }

    if (url.pathname === "/api/snapshot/delete" && request.method === "POST") {
      return handleDeleteSnapshotApi(env, request, ctx);
    }

    if (url.pathname === "/api/snapshots") {
      const sync = url.searchParams.get("sync");
      if (request.method === "POST" && sync === "1") {
        ctx.waitUntil(backfillSnapshotsFromHistory(env));
        return Response.json(
          { ok: true, message: "Rebuilding snapshot index from R2 (runs in background)." },
          { headers: cacheHeaders() },
        );
      }
      const relabelFrom = url.searchParams.get("relabel");
      const relabelTo = url.searchParams.get("to");
      if (request.method === "POST" && relabelFrom && relabelTo) {
        return handleRelabelSnapshot(env, relabelFrom, relabelTo);
      }
      if (request.method === "POST") {
        let body: Record<string, unknown>;
        try {
          body = (await request.json()) as Record<string, unknown>;
        } catch {
          return Response.json({ error: "Invalid JSON" }, { status: 400, headers: cacheHeaders() });
        }
        const dateKey = String(body.dateKey ?? "").trim();
        const action = String(body.action ?? "soft_delete").trim().toLowerCase();
        if (action === "soft_delete" || action === "delete") {
          const r = await setSnapshotSoftDeleted(env, dateKey, true);
          if (!r.ok) return Response.json({ error: r.error }, { status: r.error?.includes("No snapshot") ? 404 : 400, headers: cacheHeaders() });
          return Response.json({ ok: true, dateKey, softDeleted: true }, { headers: cacheHeaders() });
        }
        if (action === "restore" || action === "undelete") {
          const r = await setSnapshotSoftDeleted(env, dateKey, false);
          if (!r.ok) return Response.json({ error: r.error }, { status: r.error?.includes("No snapshot") ? 404 : 400, headers: cacheHeaders() });
          return Response.json({ ok: true, dateKey, restored: true }, { headers: cacheHeaders() });
        }
        return Response.json(
          { error: "Unknown action (use soft_delete or restore)" },
          { status: 400, headers: cacheHeaders() },
        );
      }
      return handleSnapshotsList(env);
    }

    if (url.pathname === "/api/mc-series/dimensions") {
      return handleMcSeriesDimensionsApi(env, url);
    }

    if (url.pathname === "/api/mc-series") {
      return handleMcSeriesApi(env, url);
    }

    if (url.pathname === "/api/latest") {
      let analysis = await getLatestActiveAnalysisFromD1(env);
      if (!analysis) analysis = await readJson<AnalysisResult>(env, "analyses/latest.json");
      if (!analysis) return new Response("Not Found", { status: 404 });
      analysis = await enrichAnalysisAssetManagerFromR2(env, analysis);
      return Response.json(analysis, { headers: cacheHeaders() });
    }

    if (url.pathname.startsWith("/api/analysis/")) {
      const dateKey = url.pathname.slice("/api/analysis/".length);
      if (!/^\d{4}-\d{2}-\d{2}$/.test(dateKey)) {
        return new Response("Invalid date key", { status: 400 });
      }
      let analysis = await readAnalysisForDateKey(env, dateKey);
      if (!analysis) return new Response("Not Found", { status: 404 });
      analysis = await enrichAnalysisAssetManagerFromR2(env, analysis);
      return Response.json(analysis, { headers: cacheHeaders() });
    }

    if (url.pathname === "/api/workbook.xlsx") {
      return handleWorkbookDownload(env, request);
    }

    if (url.pathname === "/api/watch") {
      return handleWatchApi(env, request, ctx);
    }

    if (url.pathname === "/api/schedule-mx") {
      return handleScheduleMxApi(env, request);
    }

    if (url.pathname === "/api/authz-manager") {
      return handleAuthzManagerApi(env, request);
    }

    if (url.pathname === "/api/work-order-changelog") {
      return handleWorkOrderChangelogApi(env, request);
    }

    if (url.pathname === "/api/work-order-timeline") {
      return handleWorkOrderTimelineApi(env, request);
    }

    if (url.pathname === "/api/fleet-pa") {
      const d = url.searchParams.get("date");
      if (!d || !/^\d{4}-\d{2}-\d{2}$/.test(d)) {
        return Response.json({ error: "Query date=YYYY-MM-DD is required" }, { status: 400, headers: cacheHeaders() });
      }
      try {
        const rows = await getFleetPaSnapshotForDate(env, d);
        return Response.json(
          { dateKey: d, count: rows.length, rows },
          { headers: cacheHeaders() },
        );
      } catch (e) {
        const msg = e instanceof Error ? e.message : String(e);
        return Response.json({ error: msg }, { status: 500, headers: cacheHeaders() });
      }
    }

    if (url.pathname === "/api/wo-action") {
      return handleWoActionApi(env, request);
    }

    if (url.pathname === "/api/fma-follow-up-report") {
      return handleFmaFollowUpReportApi(env, request);
    }

    if (url.pathname === "/api/yard-check.xlsx") {
      return handleYardCheckDownload(env, request);
    }

    if (url.pathname === "/api/yard-check-meta") {
      return handleYardCheckMeta(env, request);
    }

    if (url.pathname === "/api/ask") {
      return handleAskApi(env, request);
    }

    if (url.pathname === "/api/debug/scrape") {
      return handleDebugScrape(env, request);
    }

    if (url.pathname === "/api/debug/watch-counts") {
      return handleDebugWatchCounts(env);
    }

    if (url.pathname === "/api/debug/mel-headers") {
      return handleDebugMelHeaders(env, url);
    }

    if (url.pathname === "/api/mel") {
      return handleMelApi(env, url);
    }
    if (url.pathname === "/api/mel-history") {
      return handleMelHistoryApi(env, url);
    }
    if (url.pathname === "/api/mel-rollup") {
      return handleMelRollupApi(env);
    }
    if (url.pathname === "/api/mel-config") {
      return handleMelConfigApi(env, request);
    }
    if (url.pathname === "/api/mel-subdivision") {
      return handleMelSubdivisionApi(env, request);
    }
    if (url.pathname === "/api/app-config") {
      return handleAppConfigApi(env, request);
    }

    if (url.pathname === "/api/yard/roster") {
      return handleYardRosterApi(env);
    }
    if (url.pathname === "/api/yard/sightings") {
      return handleYardSightingsApi(env);
    }
    if (url.pathname === "/api/yard/photo-latest") {
      return handleYardPhotoLatestApi(env);
    }
    if (url.pathname === "/api/yard/findings") {
      return handleYardFindingsApi(env);
    }
    if (url.pathname === "/api/yard/work-orders-by-asset") {
      return handleYardWorkOrdersByAssetApi(env, url);
    }
    if (url.pathname === "/api/yard/findings/resolve") {
      return handleYardFindingResolveApi(env, request);
    }
    if (url.pathname === "/api/yard/findings/reopen") {
      return handleYardFindingReopenApi(env, request);
    }
    if (url.pathname === "/api/yard/activity") {
      return handleYardActivityApi(env, url);
    }
    if (url.pathname === "/api/yard/check") {
      return handleYardCheckApi(env, request);
    }
    if (url.pathname === "/api/yard/photo") {
      return handleYardPhotoUploadApi(env, request);
    }
    if (url.pathname === "/api/yard/photos") {
      return handleYardPhotoListApi(env, url);
    }
    const yardPhotoMatch = url.pathname.match(/^\/api\/yard\/photo\/(\d+)$/);
    if (yardPhotoMatch) {
      const id = Number.parseInt(yardPhotoMatch[1] ?? "", 10);
      if (!Number.isFinite(id)) return new Response("Invalid photo id", { status: 400 });
      return handleYardPhotoFetchApi(env, request, id);
    }
    const yardAssetMatch = url.pathname.match(/^\/api\/yard\/asset\/([^/]+)$/);
    if (yardAssetMatch) {
      const assetId = decodeURIComponent(yardAssetMatch[1] ?? "");
      return handleYardAssetDetailApi(env, assetId);
    }

    // ---------- Waiver-card API ----------
    if (url.pathname === "/api/waivers") {
      return handleWaiverSubmitApi(env, request);
    }
    if (url.pathname === "/api/waivers/pending") {
      return handleWaiverPendingApi(env);
    }
    if (url.pathname === "/api/waivers/counts") {
      return handleWaiverCountsApi(env);
    }
    const waiverVerifyPhotoMatch = url.pathname.match(/^\/api\/waivers\/verification\/(\d+)\/photo$/);
    if (waiverVerifyPhotoMatch) {
      const verId = Number.parseInt(waiverVerifyPhotoMatch[1] ?? "", 10);
      if (!Number.isFinite(verId)) return new Response("Invalid verification id", { status: 400 });
      return handleWaiverVerificationPhotoApi(env, verId);
    }
    const waiverPhotoBlobMatch = url.pathname.match(/^\/api\/waivers\/photo\/(\d+)$/);
    if (waiverPhotoBlobMatch) {
      const photoId = Number.parseInt(waiverPhotoBlobMatch[1] ?? "", 10);
      if (!Number.isFinite(photoId)) return new Response("Invalid photo id", { status: 400 });
      return handleWaiverPhotoFileApi(env, photoId);
    }
    const waiverAssetMatch = url.pathname.match(/^\/api\/waivers\/asset\/([^/]+)$/);
    if (waiverAssetMatch) {
      const assetId = decodeURIComponent(waiverAssetMatch[1] ?? "");
      return handleWaiverAssetApi(env, url, assetId);
    }
    const waiverIdActionMatch = url.pathname.match(
      /^\/api\/waivers\/(\d+)(?:\/(approve|reject|verify|delete|photo))?$/,
    );
    if (waiverIdActionMatch) {
      const id = Number.parseInt(waiverIdActionMatch[1] ?? "", 10);
      const action = waiverIdActionMatch[2] ?? "";
      if (!Number.isFinite(id)) return new Response("Invalid waiver id", { status: 400 });
      if (action === "photo") return handleWaiverPhotoApi(env, id);
      if (action === "approve" || action === "reject" || action === "verify" || action === "delete") {
        return handleWaiverActionApi(env, request, id, action);
      }
      // No action segment + DELETE = soft delete via /api/waivers/:id
      if (request.method === "DELETE") {
        return handleWaiverActionApi(env, request, id, "delete");
      }
      return handleWaiverDetailApi(env, id);
    }

    if (url.pathname === "/api/fleet/assets") {
      return handleFleetAssetsSearchApi(env, request);
    }
    if (url.pathname === "/api/fleet/units") {
      return handleFleetOwningUnitsApi(env, request);
    }
    if (url.pathname === "/api/abuse-tracker/stats") {
      return handleAbuseTrackerStatsApi(env, request);
    }
    if (url.pathname === "/api/abuse-tracker") {
      return handleAbuseTrackerListApi(env, request);
    }
    const abuseByWoMatch = url.pathname.match(/^\/api\/abuse-tracker\/by-work-order\/(.+)$/);
    if (abuseByWoMatch) {
      return handleAbuseTrackerByWorkOrderApi(env, request, abuseByWoMatch[1] ?? "");
    }
    const abuseAttMatch = url.pathname.match(/^\/api\/abuse-tracker\/attachments\/(\d+)$/);
    if (abuseAttMatch) {
      const aid = Number.parseInt(abuseAttMatch[1] ?? "", 10);
      if (!Number.isFinite(aid)) return new Response("Invalid attachment id", { status: 400 });
      return handleAbuseTrackerAttachmentApi(env, request, aid);
    }
    const abuseCaseMatch = url.pathname.match(/^\/api\/abuse-tracker\/(\d+)(?:\/(notes))?$/);
    if (abuseCaseMatch) {
      const cid = Number.parseInt(abuseCaseMatch[1] ?? "", 10);
      const sub = abuseCaseMatch[2] ?? "";
      if (!Number.isFinite(cid)) return new Response("Invalid case id", { status: 400 });
      if (sub === "notes") return handleAbuseTrackerNoteApi(env, request, cid);
      return handleAbuseTrackerCaseApi(env, request, cid);
    }

    if (url.pathname === "/api/meetings") {
      return handleMeetingsListApi(env, request);
    }
    if (url.pathname === "/api/meeting") {
      return handleMeetingCreateApi(env, request);
    }
    const meetingMatch = url.pathname.match(/^\/api\/meeting\/(\d+)(?:\/(notes|end|add|cursor|pause|zoom|note-line))?$/);
    if (meetingMatch) {
      const id = Number.parseInt(meetingMatch[1] ?? "", 10);
      const action = meetingMatch[2] ?? "";
      if (!Number.isFinite(id)) return new Response("Invalid meeting id", { status: 400 });
      if (action === "notes") return handleMeetingNoteUpsertApi(env, request, id);
      if (action === "note-line") return handleMeetingNoteLineApi(env, request, id);
      if (action === "end") return handleMeetingEndApi(env, request, id);
      if (action === "add") return handleMeetingAddWosApi(env, request, id);
      if (action === "cursor") return handleMeetingCursorApi(env, request, id);
      if (action === "pause") return handleMeetingPauseApi(env, request, id);
      if (action === "zoom") return handleMeetingZoomApi(env, request, id);
      return handleMeetingGetApi(env, request, id);
    }

    // Standalone mobile yard-check app — full-screen, no other tabs.
    if (url.pathname === "/yard") {
      return new Response(renderYardAppHtml(), {
        headers: {
          "Content-Type": "text/html; charset=utf-8",
          "Cache-Control": "private, no-store, no-cache, must-revalidate, max-age=0",
        },
      });
    }
    if (url.pathname === "/yard/manifest.webmanifest") {
      return Response.json({
        name: "Minot AFB Vehicle Management · Yard",
        short_name: "Minot VM",
        start_url: "/yard",
        display: "standalone",
        background_color: "#0a0a0d",
        theme_color: "#0a0a0d",
        orientation: "portrait",
        icons: [],
      }, {
        headers: { "Content-Type": "application/manifest+json", "Cache-Control": "public, max-age=300" },
      });
    }

    // Standalone mobile waiver-card app — no nav, full-bleed, mechanic-focused.
    if (url.pathname === "/waivers") {
      return new Response(renderWaiverAppHtml(), {
        headers: {
          "Content-Type": "text/html; charset=utf-8",
          "Cache-Control": "private, no-store, no-cache, must-revalidate, max-age=0",
        },
      });
    }
    if (url.pathname === "/waivers/manifest.webmanifest") {
      return Response.json({
        name: "Minot AFB Vehicle Management · Waivers",
        short_name: "Minot VM",
        start_url: "/waivers",
        display: "standalone",
        background_color: "#0a0a0d",
        theme_color: "#0a0a0d",
        orientation: "portrait",
        icons: [],
      }, {
        headers: { "Content-Type": "application/manifest+json", "Cache-Control": "public, max-age=300" },
      });
    }
    // Printable waiver card — server-rendered HTML so the desktop "Print"
    // button just opens this in a new window and the user hits Ctrl/Cmd-P.
    const waiverPrintMatch = url.pathname.match(/^\/waivers\/card\/([^/]+)\/print$/);
    if (waiverPrintMatch) {
      const assetId = decodeURIComponent(waiverPrintMatch[1] ?? "");
      const waivers = await listWaiversForAsset(env, assetId, { approvedOnly: true });
      return new Response(renderWaiverPrintCardHtml(assetId, waivers), {
        headers: {
          "Content-Type": "text/html; charset=utf-8",
          "Cache-Control": "private, no-store",
        },
      });
    }

    // Mobile landing — pick Waiver Card vs Yard Check before entering either app.
    if (url.pathname === "/go" || url.pathname === "/go/") {
      return new Response(renderMobileAppPickerHtml(), {
        headers: {
          "Content-Type": "text/html; charset=utf-8",
          "Cache-Control": "private, no-store, no-cache, must-revalidate, max-age=0",
        },
      });
    }
    // Stable desktop deep link: always land on dashboard Waivers -> By vehicle.
    if (url.pathname === "/desk/waivers/byvehicle") {
      const target = new URL("/", url);
      target.searchParams.set("desktop", "1");
      target.searchParams.set("tab", "waivers");
      target.searchParams.set("wv", "byvehicle");
      const asset = (url.searchParams.get("asset") ?? "").trim();
      if (asset) target.searchParams.set("asset", asset);
      return Response.redirect(target.toString(), 302);
    }

    if (url.pathname === "/" || url.pathname === "/index.html") {
      // Phones / tablets: app picker unless ?desktop=1 (full dashboard).
      const ua = request.headers.get("user-agent") || "";
      const isMobile = /Mobile|Android|iPhone|iPad|iPod/i.test(ua);
      if (isMobile && !url.searchParams.has("desktop")) {
        return Response.redirect(new URL("/go", url).toString(), 302);
      }
      return new Response(renderDashboardHtml(), {
        headers: {
          "Content-Type": "text/html; charset=utf-8",
          "Cache-Control": "private, no-store, no-cache, must-revalidate, max-age=0",
          Pragma: "no-cache",
          Expires: "0",
          "CDN-Cache-Control": "no-store",
          "Vary": "*",
        },
      });
    }

    return new Response("Not Found", { status: 404 });
  },
} satisfies ExportedHandler<Env>;

function parseYardCheckDateParam(request: Request): string | null {
  const url = new URL(request.url);
  const d = url.searchParams.get("date");
  return d && /^\d{4}-\d{2}-\d{2}$/.test(d) ? d : null;
}

async function resolveYardCheckWorkbook(
  env: Env,
  dateKey: string | null,
): Promise<
  | { ok: true; workbookKey: string; sourceFileName: string; sourceDateKey: string }
  | { ok: false; error: string }
> {
  const history = await loadMergedHistory(env);
  const latest = await readJson<AnalysisResult>(env, "analyses/latest.json");

  if (dateKey) {
    const entry = history.entries.find((e) => e.dateKey === dateKey);
    if (entry) {
      return {
        ok: true,
        workbookKey: entry.workbookKey,
        sourceFileName: entry.workbookFileName,
        sourceDateKey: entry.dateKey,
      };
    }
    return {
      ok: false,
      error: `No ETIC snapshot for ${dateKey}. Pick another date or ingest that workbook.`,
    };
  }

  const latestEntry = history.entries.length
    ? [...history.entries].sort((a, b) => a.dateKey.localeCompare(b.dateKey)).pop() ?? null
    : null;
  const workbookKey = latestEntry?.workbookKey ?? null;
  const sourceFileName = latestEntry?.workbookFileName ?? latest?.workbookFileName ?? "vehicle-etic.xlsx";
  const sourceDateKey = latestEntry?.dateKey ?? latest?.dateKey ?? "latest";

  if (!workbookKey) {
    return { ok: false, error: "No source workbook found yet. Send the ETIC email to ingest first." };
  }

  return { ok: true, workbookKey, sourceFileName, sourceDateKey };
}

async function handleYardCheckDownload(env: Env, request: Request): Promise<Response> {
  const paramDate = parseYardCheckDateParam(request);
  const resolved = await resolveYardCheckWorkbook(env, paramDate);
  if (!resolved.ok) {
    return Response.json({ ok: false, error: resolved.error }, { status: 404 });
  }
  const { workbookKey, sourceFileName, sourceDateKey } = resolved;

  const object = await env.ETIC_BUCKET.get(workbookKey);
  if (!object) {
    return Response.json(
      { ok: false, error: `Source workbook not found in R2: ${workbookKey}` },
      { status: 404 },
    );
  }

  const workbookBytes = await object.arrayBuffer();
  const source = await extractYardCheckSource(workbookBytes);
  if (!source) {
    return Response.json(
      {
        ok: false,
        error: "Could not locate a Work Orders sheet in the latest workbook.",
      },
      { status: 422 },
    );
  }

  const generatedAtIso = new Date().toISOString();
  const buffer = await generateYardCheckWorkbookBuffer(source, {
    sourceWorkbookFileName: sourceFileName,
    sourceDateKey,
    generatedAtIso,
  });

  const downloadName = `yard-check_${sourceDateKey}_${generatedAtIso.replace(/[:.]/g, "-")}.xlsx`;
  return new Response(buffer, {
    headers: {
      "Content-Type":
        "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
      "Content-Disposition": `attachment; filename="${downloadName}"`,
      "Cache-Control": "no-store",
      "X-Source-Workbook": workbookKey,
      "X-Source-Date": sourceDateKey,
      "X-Work-Order-Sheet": source.workOrderSheet ?? "",
      "X-Fleet-Sheet": source.fleetSheet ?? "",
      "X-Total-Assets": String(source.totalAssets),
      "X-Total-Work-Orders": String(source.totalWorkOrders),
    },
  });
}

type YardCheckMetaOk = {
  ok: true;
  sourceDateKey: string;
  sourceFileName: string;
  workbookKey: string;
};

type YardCheckMetaErr = { ok: false; error: string };

async function handleYardCheckMeta(env: Env, request: Request): Promise<Response> {
  const meta = await buildYardCheckMeta(env, request);
  const status = meta.ok ? 200 : 404;
  return Response.json(meta, { status, headers: cacheHeaders() });
}

async function buildYardCheckMeta(env: Env, request: Request): Promise<YardCheckMetaOk | YardCheckMetaErr> {
  const paramDate = parseYardCheckDateParam(request);
  const resolved = await resolveYardCheckWorkbook(env, paramDate);
  if (!resolved.ok) {
    return { ok: false, error: resolved.error };
  }
  const { workbookKey, sourceFileName, sourceDateKey } = resolved;

  const object = await env.ETIC_BUCKET.get(workbookKey);
  if (!object) {
    return { ok: false, error: `Source workbook not found in R2: ${workbookKey}` };
  }

  return {
    ok: true,
    sourceDateKey,
    sourceFileName,
    workbookKey,
  };
}

function cacheHeaders(): HeadersInit {
  return {
    "Cache-Control": "no-store",
  };
}

function assetManagerFromAnalysis(analysis: AnalysisResult): AssetManagerKpis {
  const am = analysis.assetManager;
  if (am && typeof am === "object") return am;
  return {
    sheetFound: false,
    mcRatePercent: null,
    fleetTotal: null,
    fmc: null,
    nmc: null,
    surplus: null,
  };
}

async function upsertSnapshotRow(env: Env, analysis: AnalysisResult, workbookKey: string): Promise<void> {
  const am = assetManagerFromAnalysis(analysis);
  const breakdown = Array.isArray(analysis.assetManagerBreakdown)
    ? analysis.assetManagerBreakdown
    : [];
  const breakdownJson = breakdown.length ? JSON.stringify(breakdown) : "";
  const analysisJson = JSON.stringify(analysis);
  const now = new Date().toISOString();
  await env.ETIC_SNAPSHOTS.prepare(
    `INSERT INTO etic_snapshots (
      date_key, workbook_key, workbook_file_name, received_at_iso,
      mc_rate, fleet_total, fmc, nmc, surplus, asset_manager_ok,
      total_rows, mel_total, visible_sheets, hidden_sheets, updated_at_iso,
      asset_manager_breakdown, analysis_json
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    ON CONFLICT(date_key) DO UPDATE SET
      workbook_key = excluded.workbook_key,
      workbook_file_name = excluded.workbook_file_name,
      received_at_iso = excluded.received_at_iso,
      mc_rate = excluded.mc_rate,
      fleet_total = excluded.fleet_total,
      fmc = excluded.fmc,
      nmc = excluded.nmc,
      surplus = excluded.surplus,
      asset_manager_ok = excluded.asset_manager_ok,
      total_rows = excluded.total_rows,
      mel_total = excluded.mel_total,
      visible_sheets = excluded.visible_sheets,
      hidden_sheets = excluded.hidden_sheets,
      updated_at_iso = excluded.updated_at_iso,
      deleted_at_iso = NULL,
      asset_manager_breakdown = CASE
        WHEN excluded.asset_manager_breakdown <> '' THEN excluded.asset_manager_breakdown
        ELSE etic_snapshots.asset_manager_breakdown
      END,
      analysis_json = excluded.analysis_json`,
  )
    .bind(
      analysis.dateKey,
      workbookKey,
      analysis.workbookFileName,
      analysis.receivedAtIso,
      am.mcRatePercent,
      am.fleetTotal,
      am.fmc,
      am.nmc,
      am.surplus,
      am.sheetFound ? 1 : 0,
      analysis.totalRowsAcrossSheets,
      analysis.melMentionsTotal,
      analysis.totalVisibleSheets,
      analysis.totalHiddenSheets,
      now,
      breakdownJson,
      analysisJson,
    )
    .run();
}

