async function handleMeetingNoteUpsertApi(env: Env, request: Request, id: number): Promise<Response> {
  if (request.method !== "PATCH" && request.method !== "POST") {
    return new Response("Method Not Allowed", { status: 405 });
  }
  const body = await readJsonBody<{ workOrderId?: string } & UpsertNoteInput & { status?: unknown }>(request);
  if (!body || !body.workOrderId) {
    return Response.json(
      { error: "Body must include workOrderId + patch fields" },
      { status: 400, headers: cacheHeaders() },
    );
  }
  const patch: UpsertNoteInput = {};
  if (body.status !== undefined) {
    if (!isValidNoteStatus(body.status)) {
      return Response.json(
        { error: "status must be pending|covered|skipped|deferred" },
        { status: 400, headers: cacheHeaders() },
      );
    }
    patch.status = body.status;
  }
  if (body.notes !== undefined) patch.notes = String(body.notes);
  if (body.dueOuts !== undefined) patch.dueOuts = String(body.dueOuts);
  const note = await upsertMeetingNote(env, id, body.workOrderId, patch);
  if (!note) return Response.json({ error: "Note not found" }, { status: 404, headers: cacheHeaders() });
  return Response.json({ note }, { headers: cacheHeaders() });
}

async function handleMeetingNoteLineApi(env: Env, request: Request, id: number): Promise<Response> {
  if (request.method !== "POST") return new Response("Method Not Allowed", { status: 405 });
  const body = await readJsonBody<{
    workOrderId?: string;
    which?: string;
    lineIndex?: number;
    done?: boolean;
  }>(request);
  if (!body || typeof body.workOrderId !== "string" || !body.workOrderId.trim()) {
    return Response.json(
      { error: "Body must include workOrderId" },
      { status: 400, headers: cacheHeaders() },
    );
  }
  if (body.which !== "notes" && body.which !== "dueOuts") {
    return Response.json(
      { error: "which must be notes or dueOuts" },
      { status: 400, headers: cacheHeaders() },
    );
  }
  const lineIndex = Number(body.lineIndex);
  if (!Number.isInteger(lineIndex) || lineIndex < 0) {
    return Response.json({ error: "lineIndex must be a non-negative integer" }, { status: 400, headers: cacheHeaders() });
  }
  const done = body.done === true;
  const note = await toggleMeetingNoteLineDone(env, id, body.workOrderId.trim(), body.which, lineIndex, done);
  if (!note) return Response.json({ error: "Not found" }, { status: 404, headers: cacheHeaders() });
  return Response.json({ note }, { headers: cacheHeaders() });
}

